 1	import * as React from 'react';
 2	
 3	import { WizardDescriptionItem } from '@catalog/wizard/components/WizardDescriptionItem';
 4	import useWizardDisksTableData from '@catalog/wizard/tabs/disks/hooks/useWizardDisksTableData';
 5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 8	import { DescriptionList, Stack, StackItem } from '@patternfly/react-core';
 9	
10	export const WizardOverviewDisksTable: React.FC<{
11	  isInlineGrid?: boolean;
12	  vm: V1VirtualMachine;
13	}> = React.memo(({ isInlineGrid, vm }) => {
14	  const [disks] = useWizardDisksTableData(vm);
15	
16	  const { t } = useKubevirtTranslation();
17	  return (
18	    <DescriptionList
19	      className="pf-v6-c-description-list"
20	      columnModifier={{ default: '3Col' }}
21	      isInlineGrid={isInlineGrid}
22	    >
23	      <WizardDescriptionItem
24	        description={
25	          <Stack>
26	            {disks.map((disk) => (
27	              <StackItem key={disk.name}>{disk.name}</StackItem>
28	            ))}
29	          </Stack>
30	        }
31	        title={t('Name')}
32	      />
33	      <WizardDescriptionItem
34	        description={
35	          <Stack>
36	            {disks.map((disk) => (
37	              <StackItem key={disk.name}>{disk.drive}</StackItem>
38	            ))}
39	          </Stack>
40	        }
41	        title={t('Drive')}
42	      />
43	      <WizardDescriptionItem
44	        description={
45	          <Stack>
46	            {disks.map((disk) => (
47	              <StackItem key={disk.name}>{readableSizeUnit(disk.size)}</StackItem>
48	            ))}
49	          </Stack>
50	        }
51	        title={t('Size')}
52	      />
53	    </DescriptionList>
54	  );
55	});
56	WizardOverviewDisksTable.displayName = 'WizardOverviewDisksTable';

